AUTH="""const User=require('../models/userModel'),bcrypt=require('bcryptjs'),jwt=require('jsonwebtoken');
exports.register=async(req,res)=>{try{if(req.user.role!=='__MANAGER__')return res.status(403).json({message:'Manager only'});if(await User.exists({username:req.body.username}))return res.status(409).json({message:'Username already exists'});if(req.body.role==='__MANAGER__')return res.status(400).json({message:'Manager accounts cannot be created here'});if((req.body.role||'__WORKER__')==='__WORKER__'&&!req.body.__ASSIGNED__)return res.status(400).json({message:'Assignment is required'});const u=await User.create({...req.body,role:req.body.role||'__WORKER__'});res.status(201).json({id:u._id,username:u.username,role:u.role});}catch(e){res.status(400).json({message:e.message});}};
exports.login=async(req,res)=>{const u=await User.findOne({username:req.body.username});if(!u||!await bcrypt.compare(req.body.password||'',u.password))return res.status(401).json({message:'Invalid credentials'});if(!u.isActive)return res.status(403).json({message:'Account is deactivated. Contact your manager.'});const token=jwt.sign({userId:u._id,role:u.role,fullName:u.fullName,__ASSIGNED__:u.__ASSIGNED__},process.env.JWT_SECRET||'pe-secret',{expiresIn:'1d'});res.json({token});};
"""
MIDDLEWARE="""const jwt=require('jsonwebtoken');exports.verifyToken=(req,res,next)=>{const t=(req.headers.authorization||'').replace(/^Bearer /,'');if(!t)return res.status(401).json({message:'Authentication required'});try{req.user=jwt.verify(t,process.env.JWT_SECRET||'pe-secret');next();}catch(e){res.status(401).json({message:'Invalid token'});}};exports.requireRole=(...roles)=>(req,res,next)=>roles.includes(req.user.role)?next():res.status(403).json({message:'Forbidden'});\n"""

PROCURE={
'masterData':"""const Supplier=require('../models/supplierModel'),Item=require('../models/itemModel');exports.createSupplier=async(req,res)=>{if(await Supplier.exists({supplierCode:req.body.supplierCode}))return res.status(409).json({message:'Duplicate supplierCode'});if(req.body.rating<0||req.body.rating>5)return res.status(400).json({message:'Rating must be 0-5'});res.status(201).json(await Supplier.create(req.body));};exports.createItem=async(req,res)=>{if(await Item.exists({itemCode:req.body.itemCode}))return res.status(409).json({message:'Duplicate itemCode'});if(req.body.standardUnitPrice<=0)return res.status(400).json({message:'Price must be positive'});res.status(201).json(await Item.create(req.body));};exports.items=async(req,res)=>{const q={};if(req.query.category)q.category=req.query.category;if(req.query.lowStock==='true')q.$expr={$lt:['$currentStock','$reorderLevel']};res.json(await Item.find(q));};""",
'purchaseOrder':"""const mongoose=require('mongoose'),PO=require('../models/purchaseOrderModel'),Supplier=require('../models/supplierModel'),Item=require('../models/itemModel'),Receipt=require('../models/goodsReceiptModel'),Tx=require('../models/procurementTransactionModel');
exports.submit=async(req,res)=>{const supplier=await Supplier.findById(req.body.supplierId);if(!supplier||supplier.status!=='active')return res.status(400).json({message:'Supplier inactive'});if(new Date(req.body.expectedDeliveryDate)<=new Date())return res.status(400).json({message:'Delivery date must be future'});const ids=req.body.items.map(x=>String(x.itemId));if(new Set(ids).size!==ids.length)return res.status(400).json({message:'Duplicate item line'});let totalAmount=0,items=[];for(const line of req.body.items){const item=await Item.findById(line.itemId);if(!item||!item.isActive||line.quantity<=0||line.unitPrice<=0)return res.status(400).json({message:'Invalid item'});const lineTotal=line.quantity*line.unitPrice;totalAmount+=lineTotal;items.push({...line,lineTotal});}const department=req.user.role==='purchasing_officer'?req.user.assignedDepartment:req.body.department;res.status(201).json(await PO.create({supplierId:supplier._id,department,items,totalAmount,expectedDeliveryDate:req.body.expectedDeliveryDate,status:'submitted',createdBy:req.user.userId}));};
exports.review=async(req,res)=>{const order=await PO.findById(req.params.id),supplier=order&&await Supplier.findById(order.supplierId);if(!order||order.status!=='submitted')return res.status(400).json({message:'Order is not submitted'});if(req.body.action==='reject'){if(!req.body.reason)return res.status(400).json({message:'Reason required'});order.status='rejected';await order.save();return res.json(order);}if(req.body.action!=='approve'||supplier.status!=='active')return res.status(400).json({message:'Invalid approval'});const s=await mongoose.startSession();await s.withTransaction(async()=>{order.status='approved';order.approvedBy=req.user.userId;supplier.totalOrders+=1;await order.save({session:s});await supplier.save({session:s});await Tx.create([{type:'order_commitment',purchaseOrderId:order._id,amount:order.totalAmount,performedBy:req.user.userId}],{session:s});});await s.endSession();res.json(order);};
exports.receive=async(req,res)=>{const order=await PO.findById(req.params.id);if(!order||!['approved','partially_received'].includes(order.status))return res.status(400).json({message:'Order cannot receive'});if(req.user.role==='purchasing_officer'&&order.department!==req.user.assignedDepartment)return res.status(403).json({message:'Wrong department'});const s=await mongoose.startSession();let value=0;try{await s.withTransaction(async()=>{for(const r of req.body.receivedItems){const line=order.items.find(x=>String(x.itemId)===String(r.itemId));if(!line||r.quantityReceived<=0||r.acceptedQuantity<0||r.acceptedQuantity>r.quantityReceived)throw Object.assign(new Error('Invalid receipt line'),{status:400});const accepted=await Receipt.aggregate([{$unwind:'$receivedItems'},{$match:{purchaseOrderId:order._id,'receivedItems.itemId':line.itemId}},{$group:{_id:null,total:{$sum:'$receivedItems.acceptedQuantity'}}}]).session(s);if((accepted[0]?.total||0)+r.acceptedQuantity>line.quantity)throw Object.assign(new Error('Accepted quantity exceeds outstanding'),{status:409});await Item.updateOne({_id:line.itemId},{$inc:{currentStock:r.acceptedQuantity}},{session:s});value+=r.acceptedQuantity*line.unitPrice;}await Receipt.create([{purchaseOrderId:order._id,receivedItems:req.body.receivedItems,receivedBy:req.user.userId,note:req.body.note}],{session:s});order.receivedAmount+=value;order.status=order.receivedAmount>=order.totalAmount?'completed':'partially_received';await order.save({session:s});await Tx.create([{type:'goods_receipt',purchaseOrderId:order._id,amount:value,performedBy:req.user.userId}],{session:s});});res.status(201).json(order);}catch(e){res.status(e.status||400).json({message:e.message});}finally{await s.endSession();}};""",
'report':"""const PO=require('../models/purchaseOrderModel'),Supplier=require('../models/supplierModel');exports.spending=async(req,res)=>res.json(await PO.aggregate([{$match:req.query.department?{department:req.query.department}:{}},{$group:{_id:{department:'$department',supplierId:'$supplierId'},orderCount:{$sum:1},committedValue:{$sum:'$totalAmount'},receivedValue:{$sum:'$receivedAmount'}}}]));exports.performance=async(req,res)=>res.json(await Supplier.find(req.query.status?{status:req.query.status}:{}).select('supplierCode name totalOrders successfulDeliveries rating'));"""}

PORT={
'container':"""const Container=require('../models/containerModel');exports.create=async(req,res)=>{if(await Container.exists({containerNumber:req.body.containerNumber}))return res.status(409).json({message:'Duplicate containerNumber'});res.status(201).json(await Container.create(req.body));};exports.list=async(req,res)=>{const q={};for(const k of ['status','type'])if(req.query[k])q[k]=req.query[k];if(req.query.yardId)q.currentYardId=req.query.yardId;if(req.query.longStay==='true')q.gateInAt={$lte:new Date(Date.now()-Number(req.query.days||7)*86400000)};res.json(await Container.find(q));};""",
'movement':"""const mongoose=require('mongoose'),Container=require('../models/containerModel'),Yard=require('../models/yardModel'),Slot=require('../models/yardSlotModel'),Move=require('../models/containerMovementModel');const compatible=(c,s)=>s.status==='available'&&s.supportedSize===c.size&&(c.type!=='refrigerated'||s.refrigeratedSupport);
exports.gateIn=async(req,res)=>{const c=await Container.findById(req.body.containerId),y=await Yard.findById(req.body.yardId),slot=await Slot.findById(req.body.slotId);if(!c||c.status!=='outside'||!y||y.status!=='active'||y.occupiedSlots>=y.maxSlots)return res.status(409).json({message:'Gate-in unavailable'});if(req.user.role==='gate_operator'&&String(req.user.assignedYard)!==String(y._id))return res.status(403).json({message:'Wrong yard'});if(!slot||String(slot.yardId)!==String(y._id)||!compatible(c,slot))return res.status(409).json({message:'Incompatible slot'});const s=await mongoose.startSession();await s.withTransaction(async()=>{c.status='in_yard';c.currentYardId=y._id;c.currentSlotId=slot._id;c.gateInAt=new Date();slot.status='occupied';slot.currentContainerId=c._id;y.occupiedSlots++;if(y.occupiedSlots>=y.maxSlots)y.status='full';await Promise.all([c.save({session:s}),slot.save({session:s}),y.save({session:s})]);await Move.create([{type:'gate_in',containerId:c._id,destinationYardId:y._id,destinationSlotId:slot._id,performedBy:req.user.userId}],{session:s});});await s.endSession();res.status(201).json(c);};
exports.relocate=async(req,res)=>{const c=await Container.findById(req.body.containerId),dst=await Yard.findById(req.body.destinationYardId),ds=await Slot.findById(req.body.destinationSlotId);if(!c||c.status!=='in_yard'||String(c.currentSlotId)===String(ds?._id)||!dst||dst.status!=='active'||!compatible(c,ds))return res.status(409).json({message:'Invalid relocation'});const sy=await Yard.findById(c.currentYardId),ss=await Slot.findById(c.currentSlotId),different=String(sy._id)!==String(dst._id);if(different&&dst.occupiedSlots>=dst.maxSlots)return res.status(409).json({message:'Destination full'});const s=await mongoose.startSession();await s.withTransaction(async()=>{ss.status='available';ss.currentContainerId=null;ds.status='occupied';ds.currentContainerId=c._id;if(different){sy.occupiedSlots--;dst.occupiedSlots++;}sy.status=sy.occupiedSlots>=sy.maxSlots?'full':'active';dst.status=dst.occupiedSlots>=dst.maxSlots?'full':'active';const oldYard=c.currentYardId,oldSlot=c.currentSlotId;c.currentYardId=dst._id;c.currentSlotId=ds._id;await Promise.all([ss.save({session:s}),ds.save({session:s}),sy.save({session:s}),dst.save({session:s}),c.save({session:s})]);await Move.create([{type:'relocation_out',containerId:c._id,sourceYardId:oldYard,sourceSlotId:oldSlot,performedBy:req.user.userId},{type:'relocation_in',containerId:c._id,destinationYardId:dst._id,destinationSlotId:ds._id,performedBy:req.user.userId}],{session:s});});await s.endSession();res.json(c);};
exports.gateOut=async(req,res)=>{if(!req.body.releaseReference)return res.status(400).json({message:'releaseReference required'});const c=await Container.findById(req.body.containerId);if(!c||c.status!=='in_yard')return res.status(400).json({message:'Container not in yard'});if(req.user.role==='gate_operator'&&String(req.user.assignedYard)!==String(c.currentYardId))return res.status(403).json({message:'Wrong yard'});const y=await Yard.findById(c.currentYardId),slot=await Slot.findById(c.currentSlotId),now=new Date(),dwellDays=Math.ceil((now-c.gateInAt)/86400000),storageCharge=Math.max(0,dwellDays-3)*150000,s=await mongoose.startSession();await s.withTransaction(async()=>{slot.status='available';slot.currentContainerId=null;y.occupiedSlots=Math.max(0,y.occupiedSlots-1);if(y.status==='full')y.status='active';c.status='released';c.currentYardId=null;c.currentSlotId=null;await Promise.all([slot.save({session:s}),y.save({session:s}),c.save({session:s})]);await Move.create([{type:'gate_out',containerId:c._id,sourceYardId:y._id,performedBy:req.user.userId,note:req.body.note}],{session:s});});await s.endSession();res.json({container:c,dwellDays,storageCharge});};""",
'report':"""const Yard=require('../models/yardModel'),Move=require('../models/containerMovementModel');exports.occupancy=async(req,res)=>res.json(await Yard.aggregate([{$match:req.query.yardId?{_id:req.query.yardId}:{}},{$project:{yardCode:1,name:1,occupiedSlots:1,maxSlots:1,utilizationPercent:{$multiply:[{$divide:['$occupiedSlots','$maxSlots']},100]}}}]));exports.history=async(req,res)=>res.json(await Move.find(req.query.type?{type:req.query.type}:{}).populate('containerId sourceYardId destinationYardId sourceSlotId destinationSlotId performedBy'));"""}

