SAFE={'pass':"""const Pass=require('../models/visitorPassModel'),Zone=require('../models/accessZoneModel');exports.create=async(req,res)=>{const from=new Date(req.body.validFrom),to=new Date(req.body.validTo),z=await Zone.findById(req.body.zoneId);if(from>=to||from<new Date())return res.status(400).json({message:'Invalid validity'});if(req.user.role==='security_officer'&&String(z.facilityId)!==String(req.user.assignedFacility))return res.status(403).json({message:'Wrong facility'});res.status(201).json(await Pass.create({...req.body,status:'pending'}));};exports.review=async(req,res)=>{const p=await Pass.findById(req.params.id);if(!p||p.status!=='pending'||!['approve','reject'].includes(req.body.action))return res.status(400).json({message:'Invalid review'});p.status=req.body.action==='approve'?'approved':'rejected';p.approvedBy=req.user.userId;await p.save();res.json(p);};exports.list=async(req,res)=>res.json(await Pass.find(req.query.status?{status:req.query.status}:{}));""",
'access':"""const mongoose=require('mongoose'),Pass=require('../models/visitorPassModel'),Facility=require('../models/facilityModel'),Zone=require('../models/accessZoneModel'),Event=require('../models/accessEventModel');exports.entry=async(req,res)=>{const p=await Pass.findOne({passCode:req.body.passCode}),now=new Date();if(!p||p.status!=='approved'||now<p.validFrom||now>p.validTo)return res.status(400).json({message:'Pass invalid'});const z=await Zone.findById(p.zoneId),f=await Facility.findById(z.facilityId);if(f.status!=='open'||z.status!=='open'||f.currentOccupancy>=f.maximumOccupancy||z.currentOccupancy>=z.maximumOccupancy)return res.status(409).json({message:'Facility or zone unavailable'});if(req.user.role==='security_officer'&&String(f._id)!==String(req.user.assignedFacility))return res.status(403).json({message:'Wrong facility'});const s=await mongoose.startSession();await s.withTransaction(async()=>{p.status='active';f.currentOccupancy++;z.currentOccupancy++;await Promise.all([p.save({session:s}),f.save({session:s}),z.save({session:s})]);await Event.create([{passId:p._id,facilityId:f._id,zoneId:z._id,type:'entry',verifiedBy:req.user.userId}],{session:s});});await s.endSession();res.json(p);};exports.exit=async(req,res)=>{const p=await Pass.findOne({passCode:req.body.passCode});if(!p||p.status!=='active')return res.status(400).json({message:'Pass not active'});const z=await Zone.findById(p.zoneId),f=await Facility.findById(z.facilityId),entry=await Event.findOne({passId:p._id,type:'entry'}).sort({createdAt:-1}),now=new Date(),visitDurationMinutes=Math.ceil((now-entry.createdAt)/60000),s=await mongoose.startSession();await s.withTransaction(async()=>{p.status='completed';f.currentOccupancy=Math.max(0,f.currentOccupancy-1);z.currentOccupancy=Math.max(0,z.currentOccupancy-1);await Promise.all([p.save({session:s}),f.save({session:s}),z.save({session:s})]);await Event.create([{passId:p._id,facilityId:f._id,zoneId:z._id,type:'exit',verifiedBy:req.user.userId}],{session:s});});await s.endSession();res.json({pass:p,visitDurationMinutes});};exports.evacuate=async(req,res)=>{if(!req.body.reason)return res.status(400).json({message:'Reason required'});const f=await Facility.findById(req.body.facilityId);if(!f)return res.status(404).json({message:'Facility not found'});const zones=await Zone.find({facilityId:f._id}),passes=await Pass.find({zoneId:{$in:zones.map(z=>z._id)},status:'active'}),s=await mongoose.startSession();await s.withTransaction(async()=>{f.status='emergency';f.currentOccupancy=0;await f.save({session:s});await Zone.updateMany({facilityId:f._id},{$set:{currentOccupancy:0}},{session:s});for(const p of passes){p.status='completed';await p.save({session:s});await Event.create([{passId:p._id,facilityId:f._id,zoneId:p.zoneId,type:'forced_exit',verifiedBy:req.user.userId,note:req.body.reason}],{session:s});}});await s.endSession();res.json({evacuatedVisitorCount:passes.length});};""",
'report':"""const Facility=require('../models/facilityModel'),Event=require('../models/accessEventModel');exports.occupancy=async(req,res)=>res.json(await Facility.aggregate([{$project:{facilityCode:1,currentOccupancy:1,maximumOccupancy:1,utilizationPercent:{$multiply:[{$divide:['$currentOccupancy','$maximumOccupancy']},100]}}}]));exports.history=async(req,res)=>res.json(await Event.find(req.query.type?{type:req.query.type}:{}).populate('passId facilityId zoneId verifiedBy'));"""}

GRANT={'grant':"""const mongoose=require('mongoose'),Project=require('../models/researchProjectModel'),Grant=require('../models/grantModel');exports.create=async(req,res)=>{const p=await Project.findById(req.body.projectId);if(!p||req.body.approvedAmount<=0)return res.status(400).json({message:'Invalid grant'});if(await Grant.exists({projectId:p._id}))return res.status(409).json({message:'Project already funded'});if(p.startDate<new Date(Date.now()-30*86400000))return res.status(400).json({message:'Project too old'});const s=await mongoose.startSession();let g;await s.withTransaction(async()=>{[g]=await Grant.create([{...req.body,remainingAmount:req.body.approvedAmount,createdBy:req.user.userId,status:'active'}],{session:s});p.status='active';await p.save({session:s});});await s.endSession();res.status(201).json(g);};exports.list=async(req,res)=>{const q=req.user.role==='project_officer'?{projectId:req.user.assignedProject}:{};if(req.query.status)q.status=req.query.status;if(req.query.lowBalance==='true')q.$expr={$lt:[{$multiply:[{$divide:['$remainingAmount','$approvedAmount']},100]},Number(req.query.threshold||20)]};res.json(await Grant.find(q));};""",
'workflow':"""const mongoose=require('mongoose'),Project=require('../models/researchProjectModel'),Grant=require('../models/grantModel'),Milestone=require('../models/milestoneModel'),Request=require('../models/fundingRequestModel'),Tx=require('../models/grantTransactionModel');exports.submitMilestone=async(req,res)=>{const m=await Milestone.findById(req.params.id);if(!m||String(m.projectId)!==String(req.user.assignedProject))return res.status(403).json({message:'Wrong project'});if(!['planned','rejected'].includes(m.status)||req.body.completionPercent<1||req.body.completionPercent>100||!req.body.evidenceNote)return res.status(400).json({message:'Invalid milestone evidence'});const p=await Project.findById(m.projectId),g=await Grant.findOne({projectId:m.projectId});if(p.status!=='active'||g.status!=='active')return res.status(400).json({message:'Project or grant inactive'});m.completionPercent=req.body.completionPercent;m.evidenceNote=req.body.evidenceNote;m.status='submitted';await m.save();res.json(m);};exports.request=async(req,res)=>{const m=await Milestone.findById(req.body.milestoneId),g=m&&await Grant.findOne({projectId:m.projectId});if(!m||String(m.projectId)!==String(req.user.assignedProject)||m.status!=='submitted'||!g||g.status!=='active'||req.body.requestedAmount<=0||req.body.requestedAmount>m.plannedBudget)return res.status(400).json({message:'Invalid funding request'});if(await Request.exists({milestoneId:m._id,status:{$in:['submitted','approved']}}))return res.status(409).json({message:'Duplicate active request'});res.status(201).json(await Request.create({grantId:g._id,milestoneId:m._id,requestedAmount:req.body.requestedAmount,status:'submitted',submittedBy:req.user.userId}));};exports.process=async(req,res)=>{const r=await Request.findById(req.params.id),g=r&&await Grant.findById(r.grantId),m=r&&await Milestone.findById(r.milestoneId),a=req.body.action;if(!r)return res.status(404).json({message:'Request not found'});if(a==='reject'){if(r.status!=='submitted'||!req.body.rejectionReason)return res.status(400).json({message:'Reason required'});r.status='rejected';r.rejectionReason=req.body.rejectionReason;m.status='rejected';await Promise.all([r.save(),m.save()]);return res.json(r);}const s=await mongoose.startSession();try{await s.withTransaction(async()=>{if(a==='approve'){if(r.status!=='submitted'||g.remainingAmount<r.requestedAmount)throw Object.assign(new Error('Insufficient grant balance'),{status:409});r.status='approved';r.reviewedBy=req.user.userId;m.status='approved';g.committedAmount+=r.requestedAmount;g.remainingAmount-=r.requestedAmount;await Tx.create([{type:'commitment',grantId:g._id,fundingRequestId:r._id,amount:r.requestedAmount,performedBy:req.user.userId}],{session:s});}else if(a==='disburse'){if(r.status!=='approved')throw new Error('Request not approved');r.status='disbursed';r.disbursedAt=new Date();g.committedAmount-=r.requestedAmount;g.disbursedAmount+=r.requestedAmount;m.status=m.completionPercent===100?'completed':'approved';await Tx.create([{type:'disbursement',grantId:g._id,fundingRequestId:r._id,amount:r.requestedAmount,performedBy:req.user.userId}],{session:s});}else throw new Error('Invalid action');await Promise.all([r.save({session:s}),m.save({session:s}),g.save({session:s})]);});res.json(r);}catch(e){res.status(e.status||400).json({message:e.message});}finally{await s.endSession();}};""",
'report':"""const Grant=require('../models/grantModel'),Milestone=require('../models/milestoneModel');exports.utilization=async(req,res)=>res.json(await Grant.aggregate([{$project:{grantCode:1,approvedAmount:1,committedAmount:1,disbursedAmount:1,remainingAmount:1,utilizationPercent:{$multiply:[{$divide:['$disbursedAmount','$approvedAmount']},100]}}}]));exports.milestones=async(req,res)=>res.json(await Milestone.aggregate([{$group:{_id:'$projectId',totalMilestones:{$sum:1},completedMilestones:{$sum:{$cond:[{$eq:['$status','completed']},1,0]}},overdueMilestones:{$sum:{$cond:[{$and:[{$lt:['$dueDate',new Date()]},{$ne:['$status','completed']}]},1,0]}}}}]));"""}

CODE={'procureflow':PROCURE,'portops':PORT,'powerbill':POWER,'safecampus':SAFE,'granttrack':GRANT}

NESTED={'procureflow':{'purchaseOrder':'items: [{ itemId: { type: mongoose.Schema.Types.ObjectId, ref: \'Item\' }, quantity: Number, unitPrice: Number, lineTotal: Number }],','goodsReceipt':'receivedItems: [{ itemId: { type: mongoose.Schema.Types.ObjectId, ref: \'Item\' }, quantityReceived: Number, acceptedQuantity: Number }],'},'powerbill':{'tariffPlan':'tiers: [{ minKwh: Number, maxKwh: Number, pricePerKwh: Number }],'}}

def _upgrade_model(key,model,code):
    replacement=NESTED.get(key,{}).get(model)
    if replacement: code=re.sub(r'^\s*(?:items|receivedItems|tiers):.*,$','  '+replacement,code,flags=re.M)
    if key=='powerbill' and model=='meterReading':code=code.replace("module.exports =", "schema.index({meterId:1,billingMonth:1},{unique:true});\nmodule.exports =")
    return code

def _user_code(meta):
    atype="mongoose.Schema.Types.ObjectId" if meta['assigned'] in ('assignedYard','assignedFacility','assignedProject') else 'String'
    return f"""const mongoose=require('mongoose'),bcrypt=require('bcryptjs');const schema=new mongoose.Schema({{username:{{type:String,unique:true,required:true}},password:{{type:String,required:true}},fullName:{{type:String,required:true}},role:{{type:String,enum:['{meta['manager']}','{meta['worker']}','auditor'],default:'{meta['worker']}'}},{meta['assigned']}:{{type:{atype},default:null}},isActive:{{type:Boolean,default:true}},createdAt:{{type:Date,default:Date.now}}}});schema.pre('save',async function(next){{if(this.isModified('password'))this.password=await bcrypt.hash(this.password,10);next();}});module.exports=mongoose.model('User',schema);\n"""

def generate_advanced_project(config,dry_run=False):
    key=config['recognized_domain'];meta=META[key];spec=config['exam_spec'];files={}
    files['package.json']=json.dumps({'name':config['project_name'].lower(),'version':'1.0.0','main':'server.js','scripts':{'start':'node server.js','dev':'nodemon server.js','seed':'node utils/seedData.js'},'dependencies':{'bcryptjs':'^2.4.3','dotenv':'^16.4.5','express':'^4.19.2','jsonwebtoken':'^9.0.2','mongoose':'^8.5.1'},'devDependencies':{'nodemon':'^3.1.4'}},indent=2)
    files['.env']='PORT=9999\nMONGODB_URI=mongodb://127.0.0.1:27017/'+config['db_name']+'\nJWT_SECRET=change-me\n'
    for model in spec['models']:files[f"models/{model['name']}Model.js"]=_upgrade_model(key,model['name'],_model_code(model))
    files['models/userModel.js']=_user_code(meta);files['middlewares/authMiddleware.js']=MIDDLEWARE
    files['utils/seedData.js']=f"""require('dotenv').config();const mongoose=require('mongoose'),User=require('../models/userModel');
(async()=>{{try{{await mongoose.connect(process.env.MONGODB_URI);await User.deleteMany();await User.create({{username:'manager1',password:'123456',fullName:'System Manager',role:'{meta['manager']}',isActive:true}});console.log('Advanced manager seed completed');}}catch(e){{console.error(e);process.exitCode=1;}}finally{{await mongoose.connection.close();}}}})();
"""
    files['controllers/authController.js']=AUTH.replace('__MANAGER__',meta['manager']).replace('__WORKER__',meta['worker']).replace('__ASSIGNED__',meta['assigned'])
    for name,code in CODE[key].items():files[f'controllers/{name}Controller.js']=code
    files['routes/authRoutes.js']="const r=require('express').Router(),c=require('../controllers/authController'),{verifyToken}=require('../middlewares/authMiddleware');r.post('/register',verifyToken,c.register);r.post('/login',c.login);module.exports=r;\n"
    routes={
      'procureflow':[("/suppliers","masterData","post","createSupplier"),("/items","masterData","post","createItem"),("/items","masterData","get","items"),("/purchase-orders","purchaseOrder","post","submit"),("/purchase-orders/:id/review","purchaseOrder","patch","review"),("/purchase-orders/:id/receive","purchaseOrder","post","receive"),("/reports/procurement-spending","report","get","spending"),("/reports/supplier-performance","report","get","performance")],
      'portops':[("/containers","container","post","create"),("/containers","container","get","list"),("/movements/gate-in","movement","post","gateIn"),("/movements/relocate","movement","post","relocate"),("/movements/gate-out","movement","post","gateOut"),("/reports/yard-occupancy","report","get","occupancy"),("/reports/movement-history","report","get","history")],
      'powerbill':[("/tariffs","account","post","tariff"),("/customers","account","post","customer"),("/customers","account","get","list"),("/readings","billing","post","reading"),("/invoices/generate","billing","post","invoice"),("/invoices/:id/payments","billing","post","payment"),("/reports/consumption-summary","report","get","consumption"),("/reports/collection-summary","report","get","collection")],
      'safecampus':[("/visitor-passes","pass","post","create"),("/visitor-passes/:id/review","pass","patch","review"),("/visitor-passes","pass","get","list"),("/access/entry","access","post","entry"),("/access/exit","access","post","exit"),("/access/emergency-evacuate","access","post","evacuate"),("/reports/occupancy-summary","report","get","occupancy"),("/reports/access-history","report","get","history")],
      'granttrack':[("/grants","grant","post","create"),("/grants","grant","get","list"),("/milestones/:id/submit","workflow","post","submitMilestone"),("/funding-requests","workflow","post","request"),("/funding-requests/:id/process","workflow","patch","process"),("/reports/grant-utilization","report","get","utilization"),("/reports/milestone-performance","report","get","milestones")],}
    mount=[]
    manager_only={'procureflow':{'createSupplier','createItem','review'},'portops':{'create','relocate'},'powerbill':{'tariff','customer','invoice','payment'},'safecampus':{'review','evacuate'},'granttrack':{'create','process'}}
    worker_manager={'procureflow':{'submit','receive'},'portops':{'gateIn','gateOut'},'powerbill':{'reading'},'safecampus':{'create','entry','exit'},'granttrack':set()}
    worker_only={'granttrack':{'submitMilestone','request'}}
    for i,(path,ctrl,method,handler) in enumerate(routes[key]):
      if ctrl=='report':allowed=[meta['manager'],'auditor']
      elif handler in manager_only.get(key,set()):allowed=[meta['manager']]
      elif handler in worker_manager.get(key,set()):allowed=[meta['manager'],meta['worker']]
      elif handler in worker_only.get(key,set()):allowed=[meta['worker']]
      else:allowed=[meta['manager'],meta['worker'],'auditor']
      role_args=','.join(repr(x) for x in allowed)
      fn=f"route{i}";files[f'routes/{fn}Routes.js']=f"const r=require('express').Router(),c=require('../controllers/{ctrl}Controller'),{{verifyToken,requireRole}}=require('../middlewares/authMiddleware');r.{method}('/',verifyToken,requireRole({role_args}),c.{handler});module.exports=r;\n";mount.append(f"app.use('{path}',require('./routes/{fn}Routes'));")
    files['server.js']="require('dotenv').config();const express=require('express'),mongoose=require('mongoose');const app=express();app.use(express.json());mongoose.connect(process.env.MONGODB_URI);app.use('/auth',require('./routes/authRoutes'));"+''.join(mount)+"app.listen(process.env.PORT||9999);module.exports=app;\n"
    files['README.md']=f"# {config['project_name']}\n\nAdvanced offline-compiled MCR backend for `{key}`. Run `npm install`, copy `.env`, then `npm start`. Sample roles: {meta['manager']}, {meta['worker']}, auditor. Test auth first, then master-data, workflow and report endpoints in rubric order.\n"
    files['GENERATION_REPORT.md']=f"# Advanced generation report\n\n- Domain: `{key}`\n- Parsed models: {len(spec['models'])}\n- Parsed APIs: {len(spec['apis'])}\n- Transaction workflow and report aggregation compiler enabled.\n"
    files['exam_spec.json']=json.dumps(spec,indent=2,ensure_ascii=False)
    output=os.path.join(config['output_dir'],config['project_name'])
    if dry_run:return files,output,[f'Advanced offline compiler: {key}']
    os.makedirs(output,exist_ok=True)
    for rel,content in files.items():
      p=os.path.join(output,rel);os.makedirs(os.path.dirname(p),exist_ok=True);open(p,'w',encoding='utf-8').write(content)
    return files,output,[f'Advanced offline compiler: {key}']
